if (! function_exists('data_simulator')) {
    function data_simulator($pattern, $count = null, $min = null, $max = null, $seed = null, $noise = null)
    {
        $count = isset($count) ? max(1, min(2000, (int)$count)) : 100;
        $min = isset($min) ? (float)$min : 0.0;
        $max = isset($max) ? (float)$max : 100.0;
        $seed = isset($seed) ? (int)$seed : 0;
        $noise = isset($noise) ? (float)$noise : 5.0;

        if ($seed !== 0) {
            mt_srand($seed);
        }

        $result = [];
        $range = $max - $min;

        switch ($pattern) {
            case 'random_walk':
                $current = ($min + $max) / 2;
                for ($i = 0; $i < $count; $i++) {
                    $step = (mt_rand() / mt_getrandmax() - 0.5) * $range * 0.1;
                    $current += $step;
                    $current = max($min, min($max, $current));
                    $result[] = round($current, 4);
                }
                break;

            case 'sine_wave':
                for ($i = 0; $i < $count; $i++) {
                    $val = $min + (sin($i * 2 * M_PI / max(1, $count * 0.25)) * 0.5 + 0.5) * $range;
                    $result[] = round($val, 4);
                }
                break;

            case 'sine_with_noise':
                for ($i = 0; $i < $count; $i++) {
                    $sine = sin($i * 2 * M_PI / max(1, $count * 0.25)) * 0.5 + 0.5;
                    $n = (mt_rand() / mt_getrandmax() - 0.5) * $noise / max(1, $range) * 0.5;
                    $val = $min + ($sine + $n) * $range;
                    $val = max($min, min($max, $val));
                    $result[] = round($val, 4);
                }
                break;

            case 'uniform_random':
                for ($i = 0; $i < $count; $i++) {
                    $result[] = round($min + mt_rand() / mt_getrandmax() * $range, 4);
                }
                break;

            case 'normal_distribution':
                // Box-Muller transform, approximate normal
                for ($i = 0; $i < $count; $i += 2) {
                    $u1 = mt_rand() / mt_getrandmax();
                    $u2 = mt_rand() / mt_getrandmax();
                    $z1 = sqrt(-2 * log(max(0.0001, $u1))) * cos(2 * M_PI * $u2);
                    $z2 = sqrt(-2 * log(max(0.0001, $u1))) * sin(2 * M_PI * $u2);
                    // Scale to range, center around mean
                    $mean = ($min + $max) / 2;
                    $std = $range / 6;
                    $v1 = $mean + $z1 * $std;
                    $v1 = max($min, min($max, $v1));
                    $result[] = round($v1, 4);
                    if ($i + 1 < $count) {
                        $v2 = $mean + $z2 * $std;
                        $v2 = max($min, min($max, $v2));
                        $result[] = round($v2, 4);
                    }
                }
                break;

            case 'linear_trend':
                for ($i = 0; $i < $count; $i++) {
                    $fraction = $i / max(1, $count - 1);
                    $val = $min + $fraction * $range;
                    $result[] = round($val, 4);
                }
                break;

            case 'constant':
                $val = ($min + $max) / 2;
                for ($i = 0; $i < $count; $i++) {
                    $result[] = round($val, 4);
                }
                break;

            default:
                return json_encode(['error' => "Unknown pattern: $pattern"]);
        }

        return json_encode([
            'data' => $result,
            'count' => count($result),
            'pattern' => $pattern,
            'min_actual' => min($result),
            'max_actual' => max($result),
            'mean' => array_sum($result) / count($result)
        ]);
    }
